Hello !

I'm posting this because I might think, it is an issue with the predict method. If I use my model trained with the usual binary, I always get the same answer, if I use the wrapper I have done in Go I always get another answer than the binary and if I use the wrapper in Python 98% of the time I get the same as the binary and 2% of the time again another answer.

Here the C++ code i'm using to wrap fastText in Go (called ```cfasttext.cpp```):

```
#include <iostream>
#include <istream>
#include <streambuf>

#include "fasttext.h"
#include "real.h"
#include "cfasttext.h"

#include "args.cc"
#include "dictionary.cc"
#include "fasttext.cc"
#include "matrix.cc"
#include "model.cc"
#include "productquantizer.cc"
#include "qmatrix.cc"
#include "utils.cc"
#include "vector.cc"

struct memoryBuffer : std::streambuf {
    memoryBuffer(char* begin, char* end) {
        this->setg(begin, begin, end);
    }
};

fasttext::FastText fasttextModel;

int predict(char *text, float *score, char *buffer, int bufferSize) {
    memoryBuffer buf(text, text + strlen(text));
    std::istream in(&buf);
    std::vector<std::pair<fasttext::real, std::string>> predictions;

    fasttextModel.predict(in, 1, predictions, 0.0);

    for (auto i = predictions.cbegin();i != predictions.cend(); i++) {
        *score = i->first;
        strncpy(buffer, i->second.c_str(), bufferSize);
    }

    return 0;
}

void loadModel(char *modelPath) {
    fasttextModel.loadModel(std::string(modelPath));
}
```
And the header (```cfasttext.h```):
```
#pragma once

#ifdef __cplusplus
extern "C" {
#endif

int predict(char *query, float *prob, char *buf, int buf_sz);
void loadModel(char *path);

#ifdef __cplusplus
}
#endif
```

And the Go code used as a wrapper:
```
package fasttext

// #cgo CXXFLAGS: -I${SRCDIR}/src -I${SRCDIR} -std=c++14
// #cgo LDFLAGS: -lstdc++ -lm
// #include <stdlib.h>
// #include "cfasttext.h"
import "C"
import (
	"fmt"
	"unsafe"
	"../text-classifier/uc"
)

type fastText struct{}

func New(path string) uc.Classifier {
	loadModel(path)

	return fastText{}
}

func loadModel(path string) {
	  C.loadModel(C.CString(path))
}

func (fastText) Predict(text string) (score float64, label string, err error) {
	  var ftProb C.float

	  buffer := (*C.char)(C.calloc(64, 1))

	  if result := C.predict(C.CString(text), &ftProb, buffer, 64); result != 0 {
		    return 0.0, "", fmt.Errorf("Something wrong happened with fastText")
	  } else {
		  label = C.GoString(buffer)
		  score = float64(ftProb)
	  }

	  C.free(unsafe.Pointer(buffer))

	  return score, label, err
}
```
Is-it coming from my C++ code or is it normal that the result changes if we are using fastText as a wrapper?

Thanks!

